// D20 die — carved numbers (engraved) on all 20 faces.
// Body: midnight blue. Numbers: gold fills at cavity floor.
const { Manifold } = api;

// ---- 1. Icosahedron --------------------------------------------------------
const phi = (1 + Math.sqrt(5)) / 2;
const R = 9;
const rawVerts = [
  [0, 1, phi], [0, -1, phi], [0, 1, -phi], [0, -1, -phi],
  [1, phi, 0], [-1, phi, 0], [1, -phi, 0], [-1, -phi, 0],
  [phi, 0, 1], [-phi, 0, 1], [phi, 0, -1], [-phi, 0, -1],
];
const sc = R / Math.sqrt(1 + phi * phi);
const V = rawVerts.map(([x, y, z]) => [x * sc, y * sc, z * sc]);
const sharpBody = Manifold.hull(V.map((v) => Manifold.sphere(0.35, 4).translate(v)));
// Round the BARE icosahedron body first — subtle casino-die edge break, not a
// blob. Numerals are carved/filled AFTER this so they stay crisp and colored
// (round()'s remeshed output would otherwise smear/discard label regions).
const ROUND_RADIUS = 0.4;
const body = api.round(sharpBody, { radius: ROUND_RADIUS });

// ---- 2. Vector helpers -----------------------------------------------------
const sub = (a, b) => [a[0]-b[0], a[1]-b[1], a[2]-b[2]];
const dot = (a, b) => a[0]*b[0] + a[1]*b[1] + a[2]*b[2];
const cross = (a, b) => [
  a[1]*b[2]-a[2]*b[1], a[2]*b[0]-a[0]*b[2], a[0]*b[1]-a[1]*b[0],
];
const norm3 = (a) => { const m = Math.hypot(a[0], a[1], a[2]); return [a[0]/m, a[1]/m, a[2]/m]; };
const RAD = 180 / Math.PI;
const rotY = (t) => [[Math.cos(t),0,Math.sin(t)],[0,1,0],[-Math.sin(t),0,Math.cos(t)]];
const rotZ = (t) => [[Math.cos(t),-Math.sin(t),0],[Math.sin(t),Math.cos(t),0],[0,0,1]];
const mv = (M, v) => [
  M[0][0]*v[0]+M[0][1]*v[1]+M[0][2]*v[2],
  M[1][0]*v[0]+M[1][1]*v[1]+M[1][2]*v[2],
  M[2][0]*v[0]+M[2][1]*v[1]+M[2][2]*v[2],
];

// ---- 3. Enumerate 20 faces ------------------------------------------------
const dist3 = (a, b) => Math.hypot(a[0]-b[0], a[1]-b[1], a[2]-b[2]);
let edge = Infinity;
for (let i = 0; i < 12; i++)
  for (let j = i+1; j < 12; j++) edge = Math.min(edge, dist3(V[i], V[j]));
const isEdge = (a, b) => Math.abs(dist3(V[a], V[b]) - edge) < 1e-6 * R;
const faces = [];
for (let a = 0; a < 12; a++)
  for (let b = a+1; b < 12; b++)
    for (let c = b+1; c < 12; c++)
      if (isEdge(a,b) && isEdge(b,c) && isEdge(a,c)) faces.push([a,b,c]);

function faceInfo(tri) {
  const c = [0,0,0];
  for (const idx of tri) for (let k = 0; k < 3; k++) c[k] += V[idx][k] / 3;
  const n = norm3(c);
  let ref = [0,0,1];
  let up = sub(ref, [n[0]*dot(ref,n), n[1]*dot(ref,n), n[2]*dot(ref,n)]);
  if (Math.hypot(up[0],up[1],up[2]) < 1e-3) {
    ref = [0,1,0];
    up = sub(ref, [n[0]*dot(ref,n), n[1]*dot(ref,n), n[2]*dot(ref,n)]);
  }
  up = norm3(up);
  return { centroid: c, normal: n, up };
}
const info = faces.map(faceInfo);

// ---- 4. 7-segment glyph builder (bars are cubes) --------------------------
const Wc = 1.55, Hc = 2.5, t = 0.5;
const ENGRAVE = 0.55;  // depth to carve into face
const CUTTER_D = 1.4;  // cutter total depth (must exceed ENGRAVE)
// Fill sits at the cavity floor: thicker so it has real volume and merges well
const FILL_D = 0.25;

const SEG = {
  A: [0, Hc-t, Wc, Hc],  G: [0, Hc/2-t/2, Wc, Hc/2+t/2],  D: [0, 0, Wc, t],
  F: [0, Hc/2, t, Hc],   B: [Wc-t, Hc/2, Wc, Hc],          E: [0, 0, t, Hc/2],
  C: [Wc-t, 0, Wc, Hc/2],
};
const DIGITS = {
  '0':['A','B','C','D','E','F'], '1':['B','C'],
  '2':['A','B','G','E','D'],    '3':['A','B','G','C','D'],
  '4':['F','G','B','C'],        '5':['A','F','G','C','D'],
  '6':['A','F','G','E','C','D'],'7':['A','B','C'],
  '8':['A','B','C','D','E','F','G'], '9':['A','B','C','D','F','G'],
};

function makeGlyph(str, depth) {
  const gap = 0.45;
  const totalW = str.length * Wc + (str.length-1) * gap;
  let x = -totalW/2 + Wc/2;
  const parts = [];
  for (const ch of str) {
    const bars = DIGITS[ch].map((name) => {
      const [x0,y0,x1,y1] = SEG[name];
      return Manifold.cube([x1-x0, y1-y0, depth]).translate([x0, y0, 0]);
    });
    parts.push(Manifold.union(bars).translate([x - Wc/2, -Hc/2, 0]));
    x += Wc + gap;
  }
  return Manifold.union(parts);
}

// ---- 5. Orient a +Z glyph onto a face (tilt + spin to face-up) -----------
function buildOriented(flat, fi) {
  const n = fi.normal;
  const theta = Math.acos(Math.max(-1, Math.min(1, n[2])));
  const azim = Math.atan2(n[1], n[0]);
  const base = (v) => mv(rotZ(azim), mv(rotY(theta), v));
  const baseUp = base([0,1,0]);
  const cosA = Math.max(-1, Math.min(1, dot(baseUp, fi.up)));
  let spin = Math.acos(cosA);
  if (dot(cross(baseUp, fi.up), n) < 0) spin = -spin;
  return flat.rotate([0,0,spin*RAD]).rotate([0,theta*RAD,0]).rotate([0,0,azim*RAD]);
}

// ---- 6. D20 standard numbering (opposite faces sum to 21) ----------------
const used = new Array(20).fill(false);
const faceNumber = new Array(20).fill(0);
let k = 1;
for (let i = 0; i < 20; i++) {
  if (used[i]) continue;
  let opp = -1;
  for (let j = 0; j < 20; j++) {
    if (j === i || used[j]) continue;
    if (dot(info[i].normal, info[j].normal) < -0.999) { opp = j; break; }
  }
  used[i] = true; faceNumber[i] = k;
  if (opp >= 0) { used[opp] = true; faceNumber[opp] = 21-k; }
  k++;
}

// ---- 7. Build cutters + gold fills ----------------------------------------
const cutters = [];
const fills = [];
for (let i = 0; i < 20; i++) {
  const fi = info[i];
  const num = String(faceNumber[i]);

  // Cutter: starts at face surface, extends ENGRAVE inward and a bit outward
  const cutter = makeGlyph(num, CUTTER_D).translate([0, 0, -ENGRAVE]);
  cutters.push(buildOriented(cutter, fi).translate(fi.centroid));

  // Gold fill: thin plate at cavity floor, extends slightly beyond cutter XY
  // to overlap cavity walls (ensures merge into body component for clean render)
  const fillFlat = makeGlyph(num, FILL_D)
    .scale([1.08, 1.08, 1])           // 8% wider to grip cavity walls
    .translate([0, 0, -ENGRAVE]);     // same start depth as cutter
  fills.push(buildOriented(fillFlat, fi).translate(fi.centroid));
}

// ---- 8. Assemble -----------------------------------------------------------
const engraved  = body.subtract(Manifold.union(cutters));
const bodyPart  = api.label(engraved,             'body',    { color: '#1a2a6c' });
const numPart   = api.label(Manifold.union(fills), 'numbers', { color: '#d4a017' });
return bodyPart.add(numPart);
